var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배…….","JPN":"ミナ先輩……","ENG":"Mina...","TWN":"米娜前輩……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"역시 미나 선배는 날 포기하지 않았어…….","JPN":"やっぱりミナ先輩は、私のことを諦めてなかった……","ENG":"I knew it... Mina wouldn't give up on me.","TWN":"果然米娜前輩沒有放棄我……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"스완, 당신이 말했죠?","JPN":"スワン、あなた言ってましたよね。","ENG":"Swan, you said it yourself, didn't you?","TWN":"史旺，你不是說了嗎？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"이 극장이 보여주는 건, 틀림없이 과거의 한 장면이라고?","JPN":"この劇場が見せてくれるのは、間違いなく過去のある瞬間だって。","ENG":"That this theater shows scenes from the past.","TWN":"這個劇場展示的，肯定是過去的一個場景吧？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그렇다면, 미나 선배가 절 구하러 오는 것도 분명 사실일 거예요! 그렇죠?","JPN":"じゃあ、ミナ先輩が私を助けに来てくれるのもきっと事実のはずです！　そうでしょう？","ENG":"If that's true, then Mina coming to save me... it has to be real too, right?","TWN":"那麼，米娜前輩來救我也一定是真的！對吧？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론이에요. 노엘.","JPN":"もちろんです、ノエル。","ENG":"Of course, Noelle.","TWN":"當然是這樣。洛艾兒。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 본 대로, 늑대는 당신을 찾고 있습니다.","JPN":"あなたが見た通り、オオカミはあなたを探しています。","ENG":"Just as you saw, the Wolf is searching for you.","TWN":"正如你所見，狼正在尋找你。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 뿐만이 아니에요. 우리의 충직한 리트리버도 제 냄새를 맡은 모양이니까요.","JPN":"それだけではありません。忠犬レトリーバーも私の匂いを嗅ぎつけたようです。","ENG":"And it seems the loyal retriever has caught my scent as well.","TWN":"不僅如此，我們忠誠的獵犬似乎也聞到了我的氣味。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"흥! 거 봐요!","JPN":"ふん！　ほら、だから言ったじゃないですか。","ENG":"Ha! See?","TWN":"哼！你看吧！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"선배만 도착하면 당신도 끝이에요! 미나 선배는 무적이거든요!","JPN":"先輩が来たら、あなたもおしまいです！　ミナ先輩は無敵なんですから！","ENG":"Once Mina gets here, it's over for you! She's unstoppable!","TWN":"前輩一到，你也完蛋了！米娜前輩可是無敵的！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"두고 봐요! 당신이 절 어떻게 괴롭혔는지, 선배한테 몽땅 일러 버릴 테니까!","JPN":"見てなさい。あなたがどうやって私を苛めたのか、先輩に全部チクってやりますから！","ENG":"Just wait! I'm going to tell her everything you did to me!","TWN":"等著瞧吧！我要把你怎麼欺負我的事情全都告訴前輩！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 그것 참 기대되는군요.","JPN":"ふふ、それは楽しみですね。","ENG":"Haha, I look forward to it.","TWN":"呵呵，真是令人期待啊。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 노엘. 이쯤 되면 한 가지 의문이 들지 않나요?","JPN":"ですが、ノエル。ここで1つ疑問が生じませんか？","ENG":"But, Noelle. By now, don't you find yourself wondering about one thing?","TWN":"但是洛艾兒。到這個時候，你不覺得有一個疑問嗎？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"의문이라고요?","JPN":"え？　疑問？","ENG":"Wonder? About what?","TWN":"疑問？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리파 차원에 유폐되어, 정보가 말소된 당신을… 늑대는 어떻게 기억하고 있을까요?","JPN":"クリファ次元に幽閉され情報が抹消されたあなたを……どうしてオオカミは覚えているのでしょう？","ENG":"You're trapped inside the Qlipha Dimension, and your information erased... And yet, how do you suppose the Wolf still remembers you?","TWN":"被囚禁在逆卡巴拉次元，資訊還被抹消的你……狼是怎麼記住的呢？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어, 어라……?","JPN":"あ、あれ……？","ENG":"H-huh...?","TWN":"啊，啊咧……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그야! 미나 선배는 멋지고 강한 사람이니까요!","JPN":"そ、それはもちろん！　ミナ先輩は格好よくて強い人ですから！","ENG":"W-well, that's because Mina is amazing and strong!","TWN":"那，那是因為米娜前輩是又帥氣又強大的人啊！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"멋지고 강하다? 그건 무슨 의미죠?","JPN":"格好よくて強い？　それはどういう意味ですか？","ENG":"Amazing and strong? What do you mean?","TWN":"帥氣又強大？那是什麼意思？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"어어… 그러니까…….","JPN":"ええと……だから……","ENG":"I mean... Uh...","TWN":"呃呃……所以……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배는… 클리포트 게임으로부터 세상을 구한 영웅이라고요……!","JPN":"ミナ先輩は……クリフォトゲームから世界を救った英雄なんです……！","ENG":"She's the hero who saved the world from the Qliphoth Game.","TWN":"米娜前輩是……在逆卡巴拉遊戲中拯救世界的英雄……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그러니까 정보 말소 같은 건… 통하지 않는 게 틀림없어요! 흥……!","JPN":"だから情報抹消なんか……通じなくて当然です！　ふん……！","ENG":"So things like information erasure... there's no way that could work on her! Hmph!","TWN":"所以像資訊抹消之類的……肯定是行不通的！哼……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 정보 말소는 하나의 자연 현상에 가깝습니다.","JPN":"どうでしょう、情報抹消は自然現象に近いものです。","ENG":"Well, information erasure is more like a natural phenomenon.","TWN":"嗯，資訊抹消更像是一種自然現象。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비가 내리면 모두가 공평하게 옷이 젖듯, 자연 현상은 인간의 강함과 약함을 가리지 않죠.","JPN":"落ちる雨があまねく全てを濡らすかのごとく、自然現象は強い人間にも弱い人間にも等しく適用されます。","ENG":"Just like rain soaks everyone equally, nature doesn't care if you're strong or weak.","TWN":"就像下雨時每個人的衣服都會被淋濕一樣，自然現象不會區分人的強弱。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그럼……?","JPN":"じゃ、じゃあ……？","ENG":"S-so what are you saying...?","TWN":"那，那……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"간단해요, 원인은 바로 당신이랍니다, 노엘 라이트.","JPN":"簡単です。原因はあなたなんですよ、ノエル・ライト。","ENG":"It's quite simple. You're the cause of all this, Noelle Wright.","TWN":"很簡單，原因就是你，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"네? 저요……?","JPN":"え？　私……？","ENG":"What? Me...?","TWN":"啊？你是在說我嗎……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 진심으로 바랐기 때문에, 늑대는 당신을 잊지 않고.","JPN":"あなたが心から願ったから、オオカミはあなたを忘れずにいる。","ENG":"Because you truly wished for it, the Wolf doesn't forget you.","TWN":"因為你真心期盼，狼不會忘記你。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 진심으로 바랐기 때문에, 늑대는 당신을 구하려는 것이죠.","JPN":"あなたが心から願ったから、オオカミはあなたを助けようとしている。……まあ、そういうことでしょう。","ENG":"Because you truly wished for it, the Wolf is trying to save you.","TWN":"因為你真心祈願，狼才會來救你。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"제가 바랐기 때문이라고요?","JPN":"私が願ったから？","ENG":"Because I wished for it?","TWN":"因為是我希望的嗎？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"떠올려보세요.","JPN":"思い出してください。","ENG":"Think carefully.","TWN":"回想一下吧。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"단 한 번이라도 어째서 당신이 늑대에게 집착하게 되었는지 의문을 가져본 적 있나요?","JPN":"たった一度でも、あなたがオオカミに執着するようになった理由について疑問を持ったことがありますか？","ENG":"Tell me, have you ever wondered why you've always been so drawn to the Wolf?","TWN":"你有沒有哪怕一次，想過為什麼你會對狼如此執著？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그야 미나 선배는……! 저는 펜릴 소대를……!","JPN":"そ、それはもちろん、ミナ先輩は……！　私はフェンリル小隊を……！","ENG":"W-well, because Mina is... The Fenrir Squad is...!","TWN":"那，那是因為米娜前輩……！我是芬里爾小隊的……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보세요. 당신의 빈약한 어휘로는 그 이유를 설명할 수 없겠죠.","JPN":"ほら。あなたの貧弱な語彙力ではその理由を説明できない。","ENG":"There it is. You can't articulate it, can you?","TWN":"看看吧。憑你那貧乏的詞彙量是解釋不了原因的。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 애초부터 당신이라는 존재는 늑대에게 접근하도록 의도된 존재였을 테니까요.","JPN":"なぜなら、最初からあなたという存在はオオカミに接近するように仕組まれた存在だったからです。","ENG":"Because from the very beginning, you were meant to be drawn to the Wolf.","TWN":"因為從一開始，你這個存在就是為了接近狼而存在的。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"의도된 존재……?","JPN":"仕組まれた存在……？","ENG":"Meant to be...?","TWN":"有意存在……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 땅에 내려온 당신이 가장 먼저 행했던 것은 늑대를 찾는 일…….","JPN":"この地に降りたあなたが真っ先に行ったことは、オオカミを探すこと……","ENG":"The moment you set foot on this world, your first instinct was to search for the Wolf.","TWN":"降臨到這片土地上的你，最先做的事情就是尋找狼……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 틀림없이 세피로트 나무가 당신에게 부여한 의무…….","JPN":"それは間違いなく、セフィロトがあなたに与えた義務……","ENG":"It must be the will of the Tree of Sephiroth, a duty etched into you...","TWN":"那無疑是生命樹賦予你的使命……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"자, 그럼 여기서 한 가지 의문을 가져볼 수 있죠.","JPN":"さて、ここで1つ疑問が生まれます。","ENG":"Now, here's a question to consider.","TWN":"那麼，在這裡可以提出一個疑問。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피로트 나무는, 세계는 어째서 당신을 늑대에게 보낸 걸까요?","JPN":"セフィロトは、世界はどうしてあなたをオオカミに送ったのでしょう？","ENG":"Why would the Tree of Sephiroth... why would this world... choose you as the one to reach the Wolf?","TWN":"生命樹，世界為什麼把你送給了狼？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……제가 생각하는 해답은 바로 이것입니다.","JPN":"……私が出した答えはこれです。","ENG":"...I believe this is the answer.","TWN":"……我認為答案就是這個。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"자, 잠깐……!?","JPN":"ま、待って……！？","ENG":"W-wait...!","TWN":"等，等等……？！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그건… 미나 선배의 울브즈베인……!?","JPN":"それは……ミナ先輩のウルブズベイン……！？","ENG":"Th-that's... Mina's Wolvesbane...!?","TWN":"那是……米娜前輩的狼之災禍……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"커헉……!","JPN":"かはっ……！","ENG":"Aack...!","TWN":"咳……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"심장을 찔렀지만, 역시 죽지 않네요, 당신은.","JPN":"やはり、心臓を貫かれても死なないのですね。あなたは。","ENG":"Even a direct stab to the heart isn't enough to kill you, it seems.","TWN":"雖然刺穿了心臟，但你果然還是沒死啊。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신을 죽이는 검인 울브즈베인과 클리포트 인자가 담긴 늑대의 피…….","JPN":"神を殺す剣であるウルブズベインと、クリフォトファクターが含まれたオオカミの血……","ENG":"The Godslayer, Wolvesbane and the Wolf's blood with Qliphoth Factor...","TWN":"弑神之劍，狼之災禍，以及蘊含神聖因數的狼之血……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"양쪽을 동시에 모방해도 당신을 죽일 수가 없어요.","JPN":"両方を同時に模倣してもあなたを殺すことができない。","ENG":"Even mimicking both still isn't enough to kill you.","TWN":"即使同時模仿兩邊，也無法殺死你。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"크으윽! 하아, 하아, 하아……!","JPN":"くうっ！　はあ、はあ、はあ……！","ENG":"Argh! *Huff* *Huff* *Huff…!*","TWN":"咳呃呃！哈啊，哈啊，哈啊……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아파, 너무 아파요… 가슴이 너무 아파서…….","JPN":"痛い、痛いよ……胸が……痛くて……","ENG":"It hurts... it hurts so much... my chest...","TWN":"痛，太痛了……胸口實在太痛了……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……이걸로 하나 더 검증되었군요.","JPN":"……これでもう1つ、検証されましたね。","ENG":"...That confirms one more thing.","TWN":"……這樣一來又驗證了一件事。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 당신이 죽기 위해서는 모방이 아니라, 늑대라는 역할 그 자체가 필요한 모양이에요.","JPN":"やはりあなたが死ぬためには模倣ではなく、オオカミという役そのものが必要そうです。","ENG":"As I thought, what's needed to end you isn't imitation, but the role of the Wolf itself.","TWN":"果然，要讓你死去，不是模仿，而是需要真正成為狼的角色。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"느, 늑대라는 역할이라고요……?","JPN":"オ、オオカミという役……？","ENG":"Th-the role of the Wolf...?","TWN":"狼，狼的角色嗎……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"ええ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"죽음의 형태까지는 분명하지 않지만, 평범한 방법으로 죽일 수 없는 당신을 죽이려면…….","JPN":"死の形は定かではありませんが、普通のやり方では殺せないあなたを殺すためには……","ENG":"I don't yet know what form your death will take. But if you can't be killed by ordinary means, then only one path remains.","TWN":"雖然不清楚死亡的形式，但要殺死你這種無法用普通方法殺死的人……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신화 속 늑대가 달을 삼키듯, 늑대가 당신에게 그 어금니를 박게 만드는 수밖에 없겠죠.","JPN":"神話の中のオオカミが月を呑み込んだごとく、オオカミがあなたをその牙で噛み潰すようにするしかない。","ENG":"Just as the Wolf of myth swallows the moon, the Wolf must be the one to sink her teeth into you.","TWN":"就像神話中的狼吞噬月亮一樣，狼只能將她的獠牙刺入你的身體。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그게 무슨 말이죠? 미나 선배가… 저를 죽인다고요……?","JPN":"どういうことですか？　ミナ先輩が……私を殺す……？","ENG":"W-what are you saying...? That Mina would... kill me...?","TWN":"那是什麼意思？米娜前輩……要殺了我……？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정확히 말하면 그 시점에서 죽는 건 당신이 아닌, 당신의 껍데기… 노엘 라이트일 거예요.","JPN":"正確に言いますと、その時点で死ぬのはあなたではなく、あなたの殻……ノエル・ライトでしょう。","ENG":"To be precise, the one who'll die at that moment won't be you. It'll be the shell named Noelle Wright.","TWN":"準確地說，那時死去的不是你，而是你的軀殼……洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계로부터 희생양이라는 역할을 짊어지게 될 가엾은 소녀.","JPN":"世界から犠牲者という役を担わせられる哀れな少女。","ENG":"A poor girl, chosen by the world to play the role of a sacrifice.","TWN":"背負著作為世界犧牲品這一使命的可憐少女。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 당신 안에 잠든 신성의 본질은 어떤 식으로든 늑대에게 넘어가겠죠.","JPN":"そしてあなたの中に眠る神聖の本質は、どんな形であれオオカミに渡される。","ENG":"And the essence of the Divinity slumbering inside you will inevitably pass on to the Wolf.","TWN":"而你體內沉睡的神聖本質無論如何都會被狼奪走。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"거짓말… 전부 거짓말이야……!","JPN":"そんなの……そんなの全部でたらめです！","ENG":"No... That's not true! It's all lies...!","TWN":"騙人……全都是騙人的……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"미나 선배는 세상을 구한 영웅이라고요!","JPN":"ミナ先輩は世界を救った英雄なんですよ……！","ENG":"Mina is a hero! She saved the world!","TWN":"米娜前輩是拯救世界的英雄啊！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신 같은 악당이 미나 선배에 대해 뭘 안다고 그래요……!","JPN":"あなたみたいな悪者に、ミナ先輩の何がわかるっていうの……！","ENG":"What would someone like you know about her, you villain!","TWN":"像你這樣的惡棍，怎麼會了解米娜前輩……！"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러는 당신은 늑대에 대해 얼마나 알고 계시죠?","JPN":"そういうあなたこそ、オオカミについてどれほどわかっていますか？","ENG":"Then let me ask you. How much do you really know about the Wolf?","TWN":"那你對狼了解多少呢？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"뭐라고요……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼……?"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 정해진 대로, 그저 본성대로, 그저 세피로트 나무가 짜둔 각본대로 늑대를 따를 뿐…….","JPN":"ただ決められた通り、本性の導くままに、セフィロトが仕組んだ脚本どおりオオカミを慕うだけ……","ENG":"You follow her blindly... by design, by instinct, by the script the Tree of Sephiroth laid out for you...","TWN":"只是按照既定的方式，只是按照本性，只是按照生命樹編寫的劇本追隨狼群……。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 단 한 번이라도 그녀의 삶에 대해서 생각해 본 적 있나요?","JPN":"たった一度でも、彼女の人生について考えたことがありますか？","ENG":"But have you ever once stopped to think about her life?","TWN":"你有沒有哪怕一次想過她的生活？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜 그녀가 항상 지쳐버린 눈빛을 하고 있었는지 생각해 본 적 있나요?","JPN":"彼女がいつも疲れた目をしている理由について、考えたことがありますか？","ENG":"Have you ever wondered why her eyes always looked so tired...?","TWN":"你有沒有想過為什麼她總是帶著疲憊的眼神？"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那，那是……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 알고 있어요.","JPN":"私は知っています。","ENG":"I know.","TWN":"我知道。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 늑대는 항상 가까운 이들의 희생을 삼켜가며 성장해 왔으니까요.","JPN":"なぜなら、オオカミは常に身近な者たちの犠牲を踏み台にして成長してきたからです。","ENG":"Because the Wolf has always grown stronger by devouring the sacrifices of those closest to her.","TWN":"因為狼總是吞噬身邊人的犧牲而成長。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그것은 세계가 규정한 거스를 수 없는 법칙 중의 하나죠.","JPN":"それは世界が定めた、逆らえない法則の1つです。","ENG":"It's an immutable law of the world, defined and enforced by its design.","TWN":"那是世界所規定的不可違背的法則之一。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계는 그녀의 성장을 위해, 가장 소중한 친구를 적으로 안배했고.","JPN":"この世界は彼女を成長させるために、もっとも大切な友人を敵に設定した。","ENG":"To ensure her growth, this world turned her dearest friend into an enemy.","TWN":"這個世界為了她的成長，把最珍貴的朋友安排成了敵人。"},"stage":{"bg":"MAINSTREAM_344010","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 세계는 그녀의 성장을 위해, 네헤모트를 아카데미의 선배로 안배했어요.","JPN":"この世界は彼女を成長させるために、ネヘモトをアカデミーの先輩に設定した。","ENG":"To ensure her growth, it placed Nehemoth in the Academy.","TWN":"這個世界為了她的成長，安排了尼赫莫特作為學院的前輩。"},"stage":{"bg":"MS_1113_1","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 이 세계는 다음으로 다가올 위협을 위해, 당신을 안배해 두었겠죠.","JPN":"おそらくこの世界は、次に迫る危機のためにあなたを用意したのでしょう。","ENG":"And perhaps... for the next threat looming ahead, the world chose you.","TWN":"也許這個世界已經安排好了你，以應對即將到來的威脅。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 껍데기 속에 잠든 신성을 늑대에게 넘겨, 종국에는 탐미엘에게 대항하기 위하여.","JPN":"その殻の中に眠る神聖をオオカミに渡し、やがて彼女をタミエルに立ち向かわせるために。","ENG":"To pass on the Divinity sealed within that shell. So that, in the end, the Wolf might stand against Tammiel.","TWN":"將沉睡在那個軀殼中的神性交給狼，最後是為了對抗塔米爾。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"然後……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"몇 번이나 세계의 멸망을 지켜본 저는 그 <color=#ffd34c>클리셰</color>를 알고 있어요.","JPN":"幾度も世界の滅亡を見届けてきた私は、その<color=#ffd34c>クリシェ</color>を知っています。","ENG":"Since I've watched the world end more times than I can count, I know how this <color=#ffd34c>cliche</color> plays out.","TWN":"我見證過幾次世界的毀滅，我知道那個<color=#ffd34c>老套情節</color>。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 이용해드리죠. 제가 바라는 모든 것을 이루기 위해.","JPN":"だから利用してあげましょう。私の望みをすべて叶えるために。","ENG":"So I'll play along... to fulfill everything I desire.","TWN":"那就利用你吧。為了實現我所期望的一切。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기꺼이… 당신 안에 잠든 신성을 가로채 드리죠, 노엘 라이트.","JPN":"喜んで……あなたの中に眠る神聖を横取りしてあげます、ノエル・ライト。","ENG":"Then I'll gladly steal the Divinity slumbering within you, Noelle Wright.","TWN":"樂意為你效勞……我將奪取你體內沉睡的神性，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그래도…….","JPN":"それでも……","ENG":"Still...","TWN":"即便如此……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그래도 저는 미나 선배를 믿을 거예요.","JPN":"それでも私はミナ先輩を信じます。","ENG":"I'll still keep believing in Mina.","TWN":"即便如此，我還是會相信米娜前輩。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"설령, 이 세상의 모든 것이 어떤 법칙에 의해 이미 정해져 있다고 하더라도…….","JPN":"たとえ、この世界のすべてが何かの法則でもう決まっていても……","ENG":"Even if everything in this world is ruled by some unchangeable law...","TWN":"即使，這個世界上的一切都已經被某種法則所決定……。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그로 인해, 결과적으로 제가 죽게 된다고 하더라도…….","JPN":"そのせいで、私が死ぬことになるとしても……","ENG":"Even if that means I'm destined to die in the end...","TWN":"即使因此，最後我會死……"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그 어떤 것도 미나 선배와 함께한 소중한 인연까지 부정할 수는 없어요.","JPN":"どれも、ミナ先輩との大切な絆を否定することはできません。","ENG":"Nothing can erase the bond I've shared with Mina.","TWN":"無論如何也不能否定我和米娜前輩之間珍貴的緣分。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그러니까 저는 마지막까지 미나 선배를 믿고 싶어요.","JPN":"だから私は最後までミナ先輩を信じます。","ENG":"That's why I want to believe in her until the very end.","TWN":"所以我想一直相信米娜前輩到最後。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요. 모든 것은 각본대로.","JPN":"いいでしょう。すべては脚本どおりに。","ENG":"Very well. Everything according to the script.","TWN":"好吧。一切都將按照劇本進行。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 늑대가 이곳으로 향하는 순간, 주사위는 던져졌습니다.","JPN":"オオカミがここへ足を運んだ瞬間、賽は投げられたようなものです。","ENG":"The moment the Wolf began heading this way, the die was cast.","TWN":"反正當狼向這裡進發的那一刻，骰子已經擲出去了。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 함께 최후의 각본을 준비하죠.","JPN":"では、一緒に最後の脚本に備えましょう。","ENG":"Let's begin... the final script.","TWN":"那麼，一起準備最後的劇本吧。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 엔딩이 누구에게 비극으로 끝나게 되는지 지켜보면서.","JPN":"そのエンディングが、誰にとっての悲劇となるか見届けるのです。","ENG":"Let's see who this ending turns out to be a tragedy for, shall we?","TWN":"看著那個結局對誰來說是悲劇的終結。"},"stage":{"bg":"THEATER","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};